messages.message:
Patch Set 1:

So I'm not a master of packing behavior, but I did check pahole and we *do* only get a benefit if the padding is removed.  (I did specifically check that.)

osc_page starts at 128 bytes.

Here's what osc_page and osc_async_page look like before the patch entirely:
struct osc_page {
        struct cl_page_slice       ops_cl;               /*     0    16 */
        struct osc_async_page      ops_oap;              /*    16    92 */
        /* --- cacheline 1 boundary (64 bytes) was 44 bytes ago --- */
        unsigned int               ops_from:12;          /*   108: 0  4 */
        unsigned int               ops_to:12;            /*   108:12  4 */
        unsigned int               ops_transfer_pinned:1; /*   108:24  4 */
        unsigned int               ops_in_lru:1;         /*   108:25  4 */
        unsigned int               ops_srvlock:1;        /*   108:26  4 */
        unsigned int               ops_intree:1;         /*   108:27  4 */

        /* XXX 4 bits hole, try to pack */

        struct list_head           ops_lru;              /*   112    16 */

        /* size: 128, cachelines: 2, members: 9 */
        /* sum members: 124 */
        /* sum bitfield members: 28 bits, bit holes: 1, sum bit holes: 4 bits */
};

struct osc_async_page {
        short unsigned int         oap_page_off;         /*     0     2 */

        /* Bitfield combined with previous fields */

        unsigned int               oap_cmd:2;            /*     0:16  4 */
        enum oap_async_flags       oap_async_flags:4;    /*     0:18  4 */
        unsigned int               oap_padding1:10;      /*     0:22  4 */
        unsigned int               oap_padding2;         /*     4     4 */
        struct list_head           oap_pending_item;     /*     8    16 */
        struct list_head           oap_rpc_item;         /*    24    16 */
        loff_t                     oap_obj_off;          /*    40     8 */
        struct ptlrpc_request *    oap_request;          /*    48     8 */
        struct osc_object *        oap_obj;              /*    56     8 */
        /* --- cacheline 1 boundary (64 bytes) --- */
        struct brw_page            oap_brw_page;         /*    64    28 */

        /* size: 92, cachelines: 2, members: 11 */
        /* last cacheline: 28 bytes */
} __attribute__((__packed__));


Here's what happens if you just remove from/to - 3 bytes of hole in osc_page:

struct osc_page {
        struct cl_page_slice       ops_cl;               /*     0    16 */
        struct osc_async_page      ops_oap;              /*    16    92 */
        /* --- cacheline 1 boundary (64 bytes) was 44 bytes ago --- */
        unsigned char              ops_transfer_pinned:1; /*   108: 0  1 */
        unsigned char              ops_in_lru:1;         /*   108: 1  1 */
        unsigned char              ops_srvlock:1;        /*   108: 2  1 */
        unsigned char              ops_intree:1;         /*   108: 3  1 */

        /* XXX 4 bits hole, try to pack */
        /* XXX 3 bytes hole, try to pack */

        struct list_head           ops_lru;              /*   112    16 */

        /* size: 128, cachelines: 2, members: 7 */
        /* sum members: 124, holes: 1, sum holes: 3 */
        /* sum bitfield members: 4 bits, bit holes: 1, sum bit holes: 4 bits */
};

(osc_async_page is unchanged)

Here's what happens if you JUST remove the padding (so, from/to are still there):

struct osc_page {
        struct cl_page_slice       ops_cl;               /*     0    16 */
        struct osc_async_page      ops_oap;              /*    16    87 */

        /* XXX 1 byte hole, try to pack */

        /* --- cacheline 1 boundary (64 bytes) was 40 bytes ago --- */
        unsigned int               ops_from:12;          /*   104: 0  4 */
        unsigned int               ops_to:12;            /*   104:12  4 */
        unsigned int               ops_transfer_pinned:1; /*   104:24  4 */
        unsigned int               ops_in_lru:1;         /*   104:25  4 */
        unsigned int               ops_srvlock:1;        /*   104:26  4 */
        unsigned int               ops_intree:1;         /*   104:27  4 */

        /* XXX 4 bits hole, try to pack */
        /* XXX 4 bytes hole, try to pack */

        struct list_head           ops_lru;              /*   112    16 */

        /* size: 128, cachelines: 2, members: 9 */
        /* sum members: 119, holes: 2, sum holes: 5 */
        /* sum bitfield members: 28 bits, bit holes: 1, sum bit holes: 4 bits */
};

truct osc_async_page {
        short unsigned int         oap_page_off;         /*     0     2 */

        /* Bitfield combined with previous fields */

        unsigned int               oap_cmd:2;            /*     0:16  4 */
        enum oap_async_flags       oap_async_flags:4;    /*     0:18  4 */

        /* XXX 2 bits hole, try to pack */
        /* Bitfield combined with next fields */

        struct list_head           oap_pending_item;     /*     3    16 */
        struct list_head           oap_rpc_item;         /*    19    16 */
        loff_t                     oap_obj_off;          /*    35     8 */
        struct ptlrpc_request *    oap_request;          /*    43     8 */
        struct osc_object *        oap_obj;              /*    51     8 */
        struct brw_page            oap_brw_page;         /*    59    28 */

        /* size: 87, cachelines: 2, members: 9 */
        /* sum members: 86 */
        /* sum bitfield members: 6 bits, bit holes: 1, sum bit holes: 2 bits */
        /* last cacheline: 23 bytes */
} __attribute__((__packed__));


And here's what happens if you remove from/to and the padding:

struct osc_page {
        struct cl_page_slice       ops_cl;               /*     0    16 */
        struct osc_async_page      ops_oap;              /*    16    87 */
        /* --- cacheline 1 boundary (64 bytes) was 39 bytes ago --- */
        unsigned char              ops_transfer_pinned:1; /*   103: 0  1 */
        unsigned char              ops_in_lru:1;         /*   103: 1  1 */
        unsigned char              ops_srvlock:1;        /*   103: 2  1 */
        unsigned char              ops_intree:1;         /*   103: 3  1 */

        /* XXX 4 bits hole, try to pack */

        struct list_head           ops_lru;              /*   104    16 */

        /* size: 120, cachelines: 2, members: 7 */
        /* sum members: 119 */
        /* sum bitfield members: 4 bits, bit holes: 1, sum bit holes: 4 bits */
        /* last cacheline: 56 bytes */
};

struct osc_async_page {
        short unsigned int         oap_page_off;         /*     0     2 */

        /* Bitfield combined with previous fields */

        unsigned int               oap_cmd:2;            /*     0:16  4 */
        enum oap_async_flags       oap_async_flags:4;    /*     0:18  4 */

        /* XXX 2 bits hole, try to pack */
        /* Bitfield combined with next fields */

        struct list_head           oap_pending_item;     /*     3    16 */
        struct list_head           oap_rpc_item;         /*    19    16 */
        loff_t                     oap_obj_off;          /*    35     8 */
        struct ptlrpc_request *    oap_request;          /*    43     8 */
        struct osc_object *        oap_obj;              /*    51     8 */
        struct brw_page            oap_brw_page;         /*    59    28 */

        /* size: 87, cachelines: 2, members: 9 */
        /* sum members: 86 */
        /* sum bitfield members: 6 bits, bit holes: 1, sum bit holes: 2 bits */
        /* last cacheline: 23 bytes */
} __attribute__((__packed__));

Now we're at 120 bytes.

I have to say, I'm getting a bit lost in the details even trying to follow it right now.
But removing the padding allows us to pack osc_page more tightly and it doesn't happen if we don't remove it.
